defmodule DevOpsAutomationWeb.CommandController do
  use DevOpsAutomationWeb, :controller

  alias DevOpsAutomation.CommandService

  def execute(conn, params) do
    case CommandService.execute_command(params) do
      {:ok, output} ->
        json(conn, %{status: "success", output: output})

      {:error, reason} ->
        conn
        |> put_status(:bad_request)
        |> json(%{status: "error", message: reason})
    end
  end

  def list_commands(conn, _params) do
    commands = [
      %{key: "git_status", description: "Get git repository status"},
      %{key: "git_pull", description: "Pull latest changes from git"},
      %{key: "git_log", description: "Show git log", params: ["count (optional)"]},
      %{key: "docker_ps", description: "List running containers"},
      %{key: "docker_images", description: "List docker images"},
      %{key: "docker_logs", description: "Get container logs", params: ["container (required)"]},
      %{key: "kubectl_get_pods", description: "List Kubernetes pods", params: ["namespace (optional)"]},
      %{key: "kubectl_get_services", description: "List Kubernetes services", params: ["namespace (optional)"]},
      %{key: "kubectl_describe", description: "Describe Kubernetes resource", params: ["resource_type (required)", "resource_name (optional)"]},
      %{key: "ls", description: "List directory contents", params: ["path (optional)"]},
      %{key: "df", description: "Show disk usage"},
      %{key: "du", description: "Show directory size", params: ["path (optional)"]},
      %{key: "systemctl_status", description: "Check service status", params: ["service (required)"]},
      %{key: "journalctl", description: "View system logs", params: ["lines (optional)"]},
      %{key: "ping", description: "Ping a host", params: ["host (required)"]},
      %{key: "curl", description: "Make HTTP request", params: ["url (required)"]},
      %{key: "npm_list", description: "List npm packages"},
      %{key: "mix_deps", description: "List Mix dependencies"},
      %{key: "mix_test", description: "Run Mix tests"}
    ]

    json(conn, %{commands: commands})
  end
end